import{_ as i,C as n,o as r,c as l,j as o,a as s,E as a,aB as c,w as d}from"./chunks/framework.BwdCTwDh.js";const w=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"reference/ziggurat.md","filePath":"reference/ziggurat.md","lastUpdated":null}'),p={name:"reference/ziggurat.md"},h={class:"jldocstring custom-block",open:""},g={class:"jldocstring custom-block",open:""};function u(f,e,b,m,y,k){const t=n("Badge");return r(),l("div",null,[o("details",h,[o("summary",null,[e[0]||(e[0]=o("a",{id:"Foresight.ziggurat",href:"#Foresight.ziggurat"},[o("span",{class:"jlbinding"},"Foresight.ziggurat")],-1)),e[1]||(e[1]=s()),a(t,{type:"info",class:"jlObjectType jlFunction",text:"Function"})]),e[3]||(e[3]=c('<div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">ziggurat</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(x; kwargs</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">...</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p>Plots a histogram with a transparent fill.</p><p><strong>Key attributes:</strong></p><p><code>linecolor</code> = <code>automatic</code>: Sets the color of the step outline.</p><p><code>color</code> = <code>@inherit patchcolor</code>: Color of the interior fill.</p><p><code>fillalpha</code> = <code>0.5</code>: Transparency of the interior fill.</p><p><code>filternan</code> = <code>true</code>: Whether to remove NaN values from the data before plotting.</p><p><strong>Plot type</strong></p><p>The plot type alias for the <code>ziggurat</code> function is <code>Ziggurat</code>.</p><p><strong>Attributes</strong></p><p><strong><code>alpha</code></strong> = <code>1.0</code> — The alpha value of the colormap or color attribute. Multiple alphas like in <code>plot(alpha=0.2, color=(:red, 0.5)</code>, will get multiplied.</p><p><strong><code>bar_labels</code></strong> = <code>nothing</code> — Labels added at the end of each bar.</p><p><strong><code>bins</code></strong> = <code>15</code> — Sets the number of bins if set to an integer or the edges of bins if set to an sorted collection of real numbers.</p><p><strong><code>clip_planes</code></strong> = <code>@inherit clip_planes automatic</code> — Clip planes offer a way to do clipping in 3D space. You can set a Vector of up to 8 <code>Plane3f</code> planes here, behind which plots will be clipped (i.e. become invisible). By default clip planes are inherited from the parent plot or scene. You can remove parent <code>clip_planes</code> by passing <code>Plane3f[]</code>.</p><p><strong><code>color</code></strong> = <code>@inherit patchcolor</code> — Color of the histogram fill</p><p><strong><code>colormap</code></strong> = <code>@inherit colormap :viridis</code> — Sets the colormap that is sampled for numeric <code>color</code>s. <code>PlotUtils.cgrad(...)</code>, <code>Makie.Reverse(any_colormap)</code> can be used as well, or any symbol from ColorBrewer or PlotUtils. To see all available color gradients, you can call <code>Makie.available_gradients()</code>.</p><p><strong><code>colorrange</code></strong> = <code>automatic</code> — The values representing the start and end points of <code>colormap</code>.</p><p><strong><code>colorscale</code></strong> = <code>identity</code> — The color transform function. Can be any function, but only works well together with <code>Colorbar</code> for <code>identity</code>, <code>log</code>, <code>log2</code>, <code>log10</code>, <code>sqrt</code>, <code>logit</code>, <code>Makie.pseudolog10</code>, <code>Makie.Symlog10</code>, <code>Makie.AsinhScale</code>, <code>Makie.SinhScale</code>, <code>Makie.LogScale</code>, <code>Makie.LuptonAsinhScale</code>, and <code>Makie.PowerScale</code>.</p><p><strong><code>cycle</code></strong> = <code>:color =&gt; :patchcolor</code> — <em>No docs available.</em></p><p><strong><code>depth_shift</code></strong> = <code>0.0</code> — Adjusts the depth value of a plot after all other transformations, i.e. in clip space, where <code>-1 &lt;= depth &lt;= 1</code>. This only applies to GLMakie and WGLMakie and can be used to adjust render order (like a tunable overdraw).</p><p><strong><code>direction</code></strong> = <code>:y</code> — Controls the direction of the bars. can be <code>:y</code> (<code>height</code> is vertical) or <code>:x</code> (<code>height</code> is horizontal).</p><p><strong><code>dodge</code></strong> = <code>automatic</code> — Dodge can be used to separate bars drawn at the same <code>position</code>. For this each bar is given an integer value corresponding to its position relative to the given <code>positions</code>. E.g. with <code>positions = [1, 1, 1, 2, 2, 2]</code> we have 3 bars at each position which can be separated by <code>dodge = [1, 2, 3, 1, 2, 3]</code>.</p><p><strong><code>dodge_gap</code></strong> = <code>0.03</code> — Sets the gap between dodged bars relative to the size of the dodged bars.</p><p><strong><code>fillalpha</code></strong> = <code>0.5</code> — Transparency of the histogram fill</p><p><strong><code>fillto</code></strong> = <code>automatic</code> — Controls the baseline of the bars. This is zero in the default <code>automatic</code> case unless the barplot is in a log-scaled <code>Axis</code>. With a log scale, the automatic default is half the minimum value because zero is an invalid value for a log scale.</p><p><strong><code>filternan</code></strong> = <code>true</code> — Whether to remove NaN values</p><p><strong><code>flip_labels_at</code></strong> = <code>Inf</code> — Sets a <code>height</code> value beyond which labels are drawn inside the bar instead of outside.</p><p><strong><code>fxaa</code></strong> = <code>true</code> — Adjusts whether the plot is rendered with fxaa (fast approximate anti-aliasing, GLMakie only). Note that some plots implement a better native anti-aliasing solution (scatter, text, lines). For them <code>fxaa = true</code> generally lowers quality. Plots that show smoothly interpolated data (e.g. image, surface) may also degrade in quality as <code>fxaa = true</code> can cause blurring.</p><p><strong><code>gap</code></strong> = <code>0</code> — Sets the gap between bars relative to their width. The new width is <code>w * (1 - gap)</code>.</p><p><strong><code>highclip</code></strong> = <code>automatic</code> — The color for any value above the colorrange.</p><p><strong><code>inspectable</code></strong> = <code>@inherit inspectable</code> — Sets whether this plot should be seen by <code>DataInspector</code>. The default depends on the theme of the parent scene.</p><p><strong><code>inspector_clear</code></strong> = <code>automatic</code> — Sets a callback function <code>(inspector, plot) -&gt; ...</code> for cleaning up custom indicators in DataInspector.</p><p><strong><code>inspector_hover</code></strong> = <code>automatic</code> — Sets a callback function <code>(inspector, plot, index) -&gt; ...</code> which replaces the default <code>show_data</code> methods.</p><p><strong><code>inspector_label</code></strong> = <code>automatic</code> — Sets a callback function <code>(plot, index, position) -&gt; string</code> which replaces the default label generated by DataInspector.</p><p><strong><code>joinstyle</code></strong> = <code>@inherit joinstyle</code> — Controls the rendering at corners. Options are <code>:miter</code> for sharp corners, <code>:bevel</code> for &quot;cut off&quot; corners, and <code>:round</code> for rounded corners. If the corner angle is below <code>miter_limit</code>, <code>:miter</code> is equivalent to <code>:bevel</code> to avoid long spikes.</p><p><strong><code>label_align</code></strong> = <code>automatic</code> — Sets the text alignment of labels.</p><p><strong><code>label_color</code></strong> = <code>@inherit textcolor</code> — Sets the color of labels.</p><p><strong><code>label_font</code></strong> = <code>@inherit font</code> — The font of the bar labels.</p><p><strong><code>label_formatter</code></strong> = <code>bar_label_formatter</code> — Formatting function which is applied to bar labels before they are passed on <code>text()</code></p><p><strong><code>label_offset</code></strong> = <code>5</code> — The distance of the labels from the bar ends in screen units. Does not apply when <code>label_position = :center</code>.</p><p><strong><code>label_position</code></strong> = <code>:end</code> — The position of each bar&#39;s label relative to the bar. Possible values are <code>:end</code> or <code>:center</code>.</p><p><strong><code>label_rotation</code></strong> = <code>0π</code> — Sets the text rotation of labels in radians.</p><p><strong><code>label_size</code></strong> = <code>@inherit fontsize</code> — The font size of the bar labels.</p><p><strong><code>linecap</code></strong> = <code>@inherit linecap</code> — Sets the type of line cap used. Options are <code>:butt</code> (flat without extrusion), <code>:square</code> (flat with half a linewidth extrusion) or <code>:round</code>.</p><p><strong><code>linecolor</code></strong> = <code>automatic</code> — Color of the histogram steps</p><p><strong><code>linestyle</code></strong> = <code>nothing</code> — Sets the dash pattern of the line. Options are <code>:solid</code> (equivalent to <code>nothing</code>), <code>:dot</code>, <code>:dash</code>, <code>:dashdot</code> and <code>:dashdotdot</code>. These can also be given in a tuple with a gap style modifier, either <code>:normal</code>, <code>:dense</code> or <code>:loose</code>. For example, <code>(:dot, :loose)</code> or <code>(:dashdot, :dense)</code>.</p><p>For custom patterns have a look at <a href="/Foresight.jl/previews/PR30/reference/ziggurat#Makie.Linestyle"><code>Makie.Linestyle</code></a>.</p><p><strong><code>linewidth</code></strong> = <code>@inherit linewidth</code> — Sets the width of the line in screen units</p><p><strong><code>lowclip</code></strong> = <code>automatic</code> — The color for any value below the colorrange.</p><p><strong><code>miter_limit</code></strong> = <code>@inherit miter_limit</code> — Sets the minimum inner join angle below which miter joins truncate. See also <code>Makie.miter_distance_to_angle</code>.</p><p><strong><code>model</code></strong> = <code>automatic</code> — Sets a model matrix for the plot. This overrides adjustments made with <code>translate!</code>, <code>rotate!</code> and <code>scale!</code>.</p><p><strong><code>n_dodge</code></strong> = <code>automatic</code> — Sets the maximum integer for <code>dodge</code>. This sets how many bars can be placed at a given position, controlling their width.</p><p><strong><code>nan_color</code></strong> = <code>:transparent</code> — The color for NaN values.</p><p><strong><code>normalization</code></strong> = <code>:none</code> — Sets the normalization applied to the histogram. Possible values are:</p><ul><li><p><code>:pdf</code>: Normalize by sum of weights and bin sizes. Resulting histogram has norm 1 and represents a probability density function.</p></li><li><p><code>:density</code>: Normalize by bin sizes only. Resulting histogram represents count density of input and does not have norm 1. Will not modify the histogram if it already represents a density (<code>h.isdensity == 1</code>).</p></li><li><p><code>:probability</code>: Normalize by sum of weights only. Resulting histogram represents the fraction of probability mass for each bin and does not have norm 1.</p></li><li><p><code>:none</code>: Do not normalize.</p></li></ul><p><strong><code>offset</code></strong> = <code>0.0</code> — Offsets all bars by the given real value. Can also be set per-bar.</p><p><strong><code>over_background_color</code></strong> = <code>automatic</code> — Sets the color of labels that are drawn outside of bars. Defaults to <code>label_color</code></p><p><strong><code>over_bar_color</code></strong> = <code>automatic</code> — Sets the color of labels that are drawn inside of/over bars. Defaults to <code>label_color</code></p><p><strong><code>overdraw</code></strong> = <code>false</code> — Controls if the plot will draw over other plots. This specifically means ignoring depth checks in GL backends</p><p><strong><code>scale_to</code></strong> = <code>nothing</code> — Scales the histogram by a common factor such that the largest bin reaches the given value. This can also be set to <code>:flip</code> to flip the direction of histogram bars without scaling them.</p><p><strong><code>space</code></strong> = <code>:data</code> — Sets the transformation space for box encompassing the plot. See <code>Makie.spaces()</code> for possible inputs.</p><p><strong><code>ssao</code></strong> = <code>false</code> — Adjusts whether the plot is rendered with ssao (screen space ambient occlusion). Note that this only makes sense in 3D plots and is only applicable with <code>fxaa = true</code>.</p><p><strong><code>stack</code></strong> = <code>automatic</code> — Similar to <code>dodge</code>, this allows bars at the same <code>positions</code> to be stacked by identifying their stack position with integers. E.g. with <code>positions = [1, 1, 1, 2, 2, 2]</code> each group of 3 bars can be stacked with <code>stack = [1, 2, 3, 1, 2, 3]</code>.</p><p><strong><code>step</code></strong> = <code>:pre</code> — The <code>step</code> parameter can take the following values:</p><ul><li><p><code>:pre</code>: horizontal part of step extends to the left of each value in <code>xs</code>.</p></li><li><p><code>:post</code>: horizontal part of step extends to the right of each value in <code>xs</code>.</p></li><li><p><code>:center</code>: horizontal part of step extends halfway between the two adjacent values of <code>xs</code>.</p></li></ul><p><strong><code>strokecolor</code></strong> = <code>@inherit patchstrokecolor</code> — Sets the outline color of bars.</p><p><strong><code>strokewidth</code></strong> = <code>@inherit patchstrokewidth</code> — Sets the outline linewidth of bars.</p><p><strong><code>transformation</code></strong> = <code>:automatic</code> — Controls the inheritance or directly sets the transformations of a plot. Transformations include the transform function and model matrix as generated by <code>translate!(...)</code>, <code>scale!(...)</code> and <code>rotate!(...)</code>. They can be set directly by passing a <code>Transformation()</code> object or inherited from the parent plot or scene. Inheritance options include:</p><ul><li><p><code>:automatic</code>: Inherit transformations if the parent and child <code>space</code> is compatible</p></li><li><p><code>:inherit</code>: Inherit transformations</p></li><li><p><code>:inherit_model</code>: Inherit only model transformations</p></li><li><p><code>:inherit_transform_func</code>: Inherit only the transform function</p></li><li><p><code>:nothing</code>: Inherit neither, fully disconnecting the child&#39;s transformations from the parent</p></li></ul><p>Another option is to pass arguments to the <code>transform!()</code> function which then get applied to the plot. For example <code>transformation = (:xz, 1.0)</code> which rotates the <code>xy</code> plane to the <code>xz</code> plane and translates by <code>1.0</code>. For this inheritance defaults to <code>:automatic</code> but can also be set through e.g. <code>(:nothing, (:xz, 1.0))</code>.</p><p><strong><code>transparency</code></strong> = <code>false</code> — Adjusts how the plot deals with transparency. In GLMakie <code>transparency = true</code> results in using Order Independent Transparency.</p><p><strong><code>visible</code></strong> = <code>true</code> — Controls whether the plot gets rendered or not.</p><p><strong><code>weights</code></strong> = <code>automatic</code> — Sets optional statistical weights.</p>',73)),a(t,{type:"info",class:"source-link",text:"source"},{default:d(()=>[...e[2]||(e[2]=[o("a",{href:"https://github.com/MakieOrg/Makie.jl/blob/v0.24.9/src/recipes.jl#L540-L748",target:"_blank",rel:"noreferrer"},"source",-1)])]),_:1})]),o("details",g,[o("summary",null,[e[4]||(e[4]=o("a",{id:"Makie.Linestyle",href:"#Makie.Linestyle"},[o("span",{class:"jlbinding"},"Makie.Linestyle")],-1)),e[5]||(e[5]=s()),a(t,{type:"info",class:"jlObjectType jlType",text:"Type"})]),e[7]||(e[7]=c(`<div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Linestyle</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(value</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">::</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Vector{&lt;:Real}</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p>A type that can be used as value for the <code>linestyle</code> keyword argument of plotting functions to arbitrarily customize the linestyle.</p><p>The <code>value</code> is a vector specifying the boundaries of the dashes in the line. Values 1 and 2 demarcate the first dash, values 2 and 3 the first gap, and so on. This means that usually, a pattern should have an odd number of values so that there&#39;s always a gap after a dash.</p><p>Here&#39;s an example in ASCII code. If we specify <code>[0, 3, 6, 11, 16]</code> then we get the following pattern:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#  0  3   6   11   16  3  6   11</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#   ---   -----     ---   -----</span></span></code></pre></div>`,5)),a(t,{type:"info",class:"source-link",text:"source"},{default:d(()=>[...e[6]||(e[6]=[o("a",{href:"https://github.com/MakieOrg/Makie.jl/blob/v0.24.9/src/conversions.jl#L1165-L1183",target:"_blank",rel:"noreferrer"},"source",-1)])]),_:1})])])}const _=i(p,[["render",u]]);export{w as __pageData,_ as default};
